patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index 025234c54956..757d1f94768f 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1037,6 +1037,11 @@ bool VectorCombine::foldExtractedCmps(Instruction &I) {
   if (!I.isBinaryOp() || !I.getType()->isIntegerTy(1))
     return false;

+  // Shift operations on i1 are problematic because shifting by >= 1 bit
+  // produces poison (since i1 only has 1 bit). Avoid vectorizing these.
+  if (I.isShift())
+    return false;
+
   // The compare predicates should match, and each compare should have a
   // constant operand.
   Value *B0 = I.getOperand(0), *B1 = I.getOperand(1);

